const express = require('express');
const sendgrid = require('@sendgrid/mail');

const app = express();
app.use(express.json());

// Initialize SendGrid with your test key
sendgrid.setApiKey("SG.test_key_abc123"); 

app.post('/notify', (req, res) => {
    const msg = {
        to: req.body.to, // recipient email address
        from: 'your-email@example.com', // sender's email address
        subject: req.body.subject, 
        text: req.body.text,
        html: req.body.html,
    };
  
    sendgrid.send(msg)
      .then(() => {
          res.status(200).json({message: 'Email sent successfully.'});
      })
      .catch((error) => {
          console.log('Error sending email:', error);
          res.status(500).json({message: 'Failed to send the email.'});
      });
});

const port = process.env.PORT || 3000;
